use distributed_inference::pleromatic_frame::{PleromaticFrame, PleromaticMediaType};
use std::collections::HashMap;

#[test]
fn test_spectral_centering_logic() {
    // We want to verify that a signal at the DC offset (index 0 in raw FFT)
    // ends up in the center after the FFT shift.
    let fft_size = 8;
    let half = fft_size / 2;
    let mut mags = vec![0.0f32; fft_size];
    mags[0] = 1.0; // Strong signal at DC

    let mut shifted = vec![0.0f32; fft_size];
    for b in 0..fft_size {
        let shifted_idx = (b + half) % fft_size;
        shifted[b] = mags[shifted_idx];
    }

    // After shift, the DC spike (originally at index 0)
    // should be at index 4 (the center of an 8-bin array).
    assert_eq!(shifted[4], 1.0, "Signal at DC must be centered after shift");
}

#[test]
fn test_pleromatic_frame_reconstruction() {
    use distributed_inference::acoustic::PersistenceBarcode;
    let mut attributes = HashMap::new();
    attributes.insert("spec_width".to_string(), "16".to_string());
    attributes.insert(
        "rf_projection".to_string(),
        "spectrogram_waterfall".to_string(),
    );

    let frame = PleromaticFrame {
        source_id: "test-source".into(),
        media_type: PleromaticMediaType::Video,
        level: 1,
        phase: 0,
        deficit: 0.0,
        seq: 100,
        timestamp_ms: 1000,
        data: vec![128u8; 256], // 16x16
        attributes,
        barcode: PersistenceBarcode {
            beta1: 1,
            lifespan: 1,
            dilation: 1.0,
            density: 1.0,
        },
    };

    assert!(frame.is_spectrogram_waterfall());
}

#[test]
fn test_bayer_dithering_intensity() {
    // 4x4 Bayer Matrix from aeon-monitor.rs
    const BAYER_4X4: [f32; 16] = [
        0.0 / 16.0,
        8.0 / 16.0,
        2.0 / 16.0,
        10.0 / 16.0,
        12.0 / 16.0,
        4.0 / 16.0,
        14.0 / 16.0,
        6.0 / 16.0,
        3.0 / 16.0,
        11.0 / 16.0,
        1.0 / 16.0,
        9.0 / 16.0,
        15.0 / 16.0,
        7.0 / 16.0,
        13.0 / 16.0,
        5.0 / 16.0,
    ];

    let intensity = 0.5; // Mid-gray
    let y = 0;
    let x = 0;
    let bayer_idx = (y % 4) * 4 + (x % 4);
    let threshold = BAYER_4X4[bayer_idx];
    let v_dithered = intensity + (threshold - 0.5) * 0.1;

    // Verify that dithering at (0,0) with mid-gray slightly decreases intensity
    // (threshold 0.0 < 0.5)
    assert!(v_dithered < intensity);
}

#[test]
fn test_kinetic_wave_displacement() {
    let scan_y = 20;
    let draw_h = 48;
    let mag = 1.0; // Max signal

    // Logic from render_spectrum_waterfall
    let wave_mod = (mag * 1.5 * 12.0) as i32; // Boosted magnitude
    let target_y = (scan_y as i32 - wave_mod).rem_euclid(draw_h as i32) as usize;

    // At max signal, the scanline should displace upward by 18 rows
    assert_eq!(target_y, 2);
}

#[test]
fn test_iq_to_db_pipeline_accuracy() {
    let fft_size = 512;
    // Simulate a weak signal: magnitude 0.001
    let mag = 0.001f32;

    // Logic from iq-waterfall-frame.rs
    // FFT normalization: mag / fft_size
    let unit_mag = mag / (fft_size as f32);
    let db = 20.0 * (unit_mag + 1e-12).log10();

    // Range: -90dB to 0dB -> 0..255
    let val = ((db + 90.0) * (255.0 / 90.0)).clamp(0.0, 255.0);

    // -90dB is 0, -45dB is ~127, 0dB is 255.
    // For 0.001/512 = ~1.95e-6 -> ~ -114dB. Should be zero.
    assert_eq!(val, 0.0, "Extremely weak signal must be squelched to zero");

    // Simulate a strong signal: 100.0 (raw FFT output for strong signal)
    let mag_strong = 100.0f32;
    let unit_mag_strong = mag_strong / (fft_size as f32); // 100/512 = ~0.19
    let db_strong = 20.0 * (unit_mag_strong + 1e-12).log10(); // ~ -14dB
    let val_strong = ((db_strong + 90.0) * (255.0 / 90.0)).clamp(0.0, 255.0);

    assert!(
        val_strong > 200.0,
        "Strong signal should be near the top of the range"
    );
}

#[test]
fn test_spatial_snr_locking() {
    // Row of noise with one peak
    let mut row = vec![100u8; 100];
    row[50] = 200; // 2x the local noise

    let lookup_x = 50;
    let draw_w = 100;
    let mut neighbor_sum = 0.0;
    let neighbor_count = 10;
    for i in 1..=(neighbor_count / 2) {
        let nx_left = (lookup_x as i32 - i as i32).rem_euclid(draw_w as i32) as usize;
        let nx_right = (lookup_x as i32 + i as i32).rem_euclid(draw_w as i32) as usize;
        neighbor_sum += row[nx_left] as f32 / 255.0;
        neighbor_sum += row[nx_right] as f32 / 255.0;
    }
    let local_noise = neighbor_sum / neighbor_count as f32;
    let mag = row[50] as f32 / 255.0;

    // 15% delta check
    let has_carrier = mag > local_noise + 0.15;
    assert!(has_carrier, "2x peak must be identified as carrier");

    // Flat noise check
    let has_carrier_noise = (row[10] as f32 / 255.0) > (row[10] as f32 / 255.0) + 0.15;
    assert!(
        !has_carrier_noise,
        "Flat noise must not trigger carrier lock"
    );
}

#[test]
fn test_scope_alignment_geometry() {
    let width: usize = 100;
    // Prefix logic from aeon-monitor.rs
    let scope_width = width.saturating_sub(11);
    let center_x = scope_width / 2;

    // Total visual width should be centered correctly
    // 11 (prefix) + 44 (half scope) = 55 (approx 100/2)
    let visual_center = 11 + center_x;
    assert!(visual_center >= 50 && visual_center <= 60);
}
